-    if (report != NULL) {
-        asx_codec_equiv_report_init(report);
-    }
-
-    /* Compare all semantic fields — codec is explicitly excluded */
-
-    if (!asx_equiv_str_eq(a->scenario_id, b->scenario_id)) {
